// Package remote implements a Provisioner that delegates the cluster
// lifecycle to a remote `talosctl remote-provision-launch` daemon over
// gRPC. The server runs the in-process QEMU provisioner unchanged.
//
// Local-computable methods (network endpoints, interface selectors, disk
// naming) mirror the QEMU provisioner so configs generated by talosctl
// match what the server will actually do.
package remote

import (
	"context"
	"errors"
	"fmt"
	"io"
	"os"
	"sync"

	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/credentials/insecure"
	"google.golang.org/grpc/status"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.com/siderolabs/talos/pkg/machinery/cel"
	"github.com/siderolabs/talos/pkg/machinery/cel/celenv"
	"github.com/siderolabs/talos/pkg/machinery/config"
	"github.com/siderolabs/talos/pkg/machinery/config/bundle"
	configconfig "github.com/siderolabs/talos/pkg/machinery/config/config"
	"github.com/siderolabs/talos/pkg/machinery/config/configpatcher"
	"github.com/siderolabs/talos/pkg/machinery/config/container"
	"github.com/siderolabs/talos/pkg/machinery/config/generate"
	networkcfg "github.com/siderolabs/talos/pkg/machinery/config/types/network"
	"github.com/siderolabs/talos/pkg/machinery/config/types/v1alpha1"
	"github.com/siderolabs/talos/pkg/machinery/nethelpers"
	"github.com/siderolabs/talos/pkg/provision"
	remoteprovisionpb "github.com/siderolabs/talos/pkg/provision/api"
)

// ProviderName is the name of the remote provisioner.
const ProviderName = "remote"

// Provisioner is the remote provisioner — a gRPC client delegating to a
// remote-provision daemon.
type Provisioner struct {
	endpoint string

	mu         sync.Mutex
	conn       *grpc.ClientConn
	client     remoteprovisionpb.RemoteProvisionServiceClient
	serverArch string
}

// NewProvisioner builds a remote provisioner targeting endpoint.
//
// endpoint is a host:port pair (e.g. "cluster-server.example:50100") that
// the gRPC client will dial. No connection is opened until the first RPC.
func NewProvisioner(_ context.Context, endpoint string) (provision.Provisioner, error) {
	if endpoint == "" {
		return nil, errors.New("remote provisioner: endpoint is required")
	}

	return &Provisioner{endpoint: endpoint}, nil
}

// dial lazily establishes the gRPC connection.
func (p *Provisioner) dial(ctx context.Context) (remoteprovisionpb.RemoteProvisionServiceClient, error) {
	p.mu.Lock()
	defer p.mu.Unlock()

	if p.client != nil {
		return p.client, nil
	}

	conn, err := grpc.NewClient(p.endpoint, grpc.WithTransportCredentials(insecure.NewCredentials()))
	if err != nil {
		return nil, fmt.Errorf("remote: dial %s: %w", p.endpoint, err)
	}

	// Probe the connection with a Ping so callers see "server unreachable"
	// upfront rather than getting it buried inside a Create stream. The
	// Ping also tells us the server's architecture.
	client := remoteprovisionpb.NewRemoteProvisionServiceClient(conn)

	pong, err := client.Ping(ctx, &emptypb.Empty{})
	if err != nil {
		conn.Close() //nolint:errcheck // releasing the just-opened conn on the failure path

		return nil, fmt.Errorf("remote: ping %s: %w", p.endpoint, err)
	}

	p.conn = conn
	p.client = client
	p.serverArch = pong.GetHostArch()

	return client, nil
}

// ServerArch returns the architecture of the remote server ("amd64" /
// "arm64"). Callers should target this arch for remote cluster creation —
// the server runs the VMs, so its arch is what matters.
func (p *Provisioner) ServerArch(ctx context.Context) (string, error) {
	if _, err := p.dial(ctx); err != nil {
		return "", err
	}

	p.mu.Lock()
	defer p.mu.Unlock()

	return p.serverArch, nil
}

// Create provisions a cluster on the remote server.
//
// The ClusterRequest is JSON-encoded and streamed to the server, which
// runs the in-process QEMU provisioner. Progress events are written to
// stderr; the terminal event carries the JSON-encoded Cluster.
//
//nolint:gocyclo
func (p *Provisioner) Create(ctx context.Context, req provision.ClusterRequest, opts ...provision.Option) (provision.Cluster, error) {
	client, err := p.dial(ctx)
	if err != nil {
		return nil, err
	}

	payload, err := MarshalClusterRequest(req)
	if err != nil {
		return nil, fmt.Errorf("remote: marshal cluster request: %w", err)
	}

	optsPayload, err := MarshalOptions(opts)
	if err != nil {
		return nil, fmt.Errorf("remote: marshal options: %w", err)
	}

	// Upload local-file boot assets to the server's cache; URL assets are
	// left for the server to fetch itself.
	artifactPaths, err := p.uploadArtifacts(ctx, client, &req)
	if err != nil {
		return nil, fmt.Errorf("remote: upload artifacts: %w", err)
	}

	stream, err := client.Create(ctx, &remoteprovisionpb.CreateRequest{
		ClusterRequest: payload,
		Options:        optsPayload,
		ArtifactPaths:  artifactPaths,
	})
	if err != nil {
		return nil, fmt.Errorf("remote: create rpc: %w", err)
	}

	logTo := resolveLogWriter(opts)

	var clusterPayload []byte

	for {
		ev, err := stream.Recv()
		if errors.Is(err, io.EOF) {
			break
		}

		if err != nil {
			return nil, fmt.Errorf("remote: create stream: %w", err)
		}

		switch e := ev.GetEvent().(type) {
		case *remoteprovisionpb.CreateEvent_Status:
			fmt.Fprintln(logTo, e.Status)
		case *remoteprovisionpb.CreateEvent_Warning:
			fmt.Fprintf(logTo, "warning: %s\n", e.Warning)
		case *remoteprovisionpb.CreateEvent_Cluster:
			clusterPayload = e.Cluster
		}
	}

	if clusterPayload == nil {
		return nil, errors.New("remote: server completed Create without returning a cluster")
	}

	return UnmarshalCluster(clusterPayload)
}

// Destroy tears down a cluster on the remote server.
func (p *Provisioner) Destroy(ctx context.Context, cluster provision.Cluster, _ ...provision.Option) error {
	name := cluster.Info().ClusterName

	client, err := p.dial(ctx)
	if err != nil {
		return err
	}

	if _, err = client.Destroy(ctx, &remoteprovisionpb.DestroyRequest{ClusterName: name}); err == nil {
		return nil
	}

	// The server's network teardown can briefly drop the gRPC connection
	// just as Destroy completes, surfacing as a transport error even
	// though the cluster was removed. Re-check by name: if it's gone, the
	// destroy succeeded.
	if status.Code(err) == codes.Unavailable {
		p.reset()

		if _, reflectErr := p.Reflect(ctx, name, ""); status.Code(reflectErr) == codes.NotFound {
			return nil
		}
	}

	return fmt.Errorf("remote: destroy rpc: %w", err)
}

// reset drops the cached gRPC connection so the next call re-dials. Used
// after a transport error leaves the connection unusable.
func (p *Provisioner) reset() {
	p.mu.Lock()
	defer p.mu.Unlock()

	if p.conn != nil {
		p.conn.Close() // nolint:errcheck
	}

	p.conn = nil
	p.client = nil
}

// Reflect looks up a previously-created cluster by name on the server.
//
// stateDirectory is ignored — the server owns its own state directory.
func (p *Provisioner) Reflect(ctx context.Context, clusterName, _ string) (provision.Cluster, error) {
	client, err := p.dial(ctx)
	if err != nil {
		return nil, err
	}

	resp, err := client.Reflect(ctx, &remoteprovisionpb.ReflectRequest{ClusterName: clusterName})
	if err != nil {
		return nil, fmt.Errorf("remote: reflect rpc: %w", err)
	}

	return UnmarshalCluster(resp.GetCluster())
}

// StreamLogs tails QEMU console logs from the remote-provision server,
// writing each line to w prefixed with its machine name. An empty
// machineName streams every machine in the cluster; follow keeps the
// stream open (tail -F).
func (p *Provisioner) StreamLogs(ctx context.Context, clusterName, machineName string, follow bool, w io.Writer) error {
	client, err := p.dial(ctx)
	if err != nil {
		return err
	}

	stream, err := client.StreamLogs(ctx, &remoteprovisionpb.LogsRequest{
		ClusterName: clusterName,
		MachineName: machineName,
		Follow:      follow,
	})
	if err != nil {
		return fmt.Errorf("remote: stream logs rpc: %w", err)
	}

	// A specific machine was requested — every line is from it, so skip
	// the machine-name prefix. Tailing all machines keeps the prefix.
	prefix := machineName == ""

	for {
		data, err := stream.Recv()
		if errors.Is(err, io.EOF) {
			return nil
		}

		if err != nil {
			return fmt.Errorf("remote: logs stream: %w", err)
		}

		if prefix {
			fmt.Fprintf(w, "[%s] %s\n", data.GetMachineName(), data.GetLine())
		} else {
			fmt.Fprintln(w, data.GetLine())
		}
	}
}

// Close releases any held gRPC connection.
func (p *Provisioner) Close() error {
	p.mu.Lock()
	defer p.mu.Unlock()

	if p.conn == nil {
		return nil
	}

	err := p.conn.Close()
	p.conn = nil
	p.client = nil

	return err
}

func resolveLogWriter(opts []provision.Option) io.Writer {
	options := &provision.Options{LogWriter: os.Stderr}
	for _, o := range opts {
		o(options) // nolint:errcheck
	}

	if options.LogWriter == nil {
		return os.Stderr
	}

	return options.LogWriter
}

// GenOptions returns the same config-generate options the QEMU provisioner
// emits, so the configs talosctl generates locally match what the server's
// in-process QEMU provisioner expects.
//
//nolint:gocyclo
func (p *Provisioner) GenOptions(networkReq provision.NetworkRequest, contract *config.VersionContract) ([]generate.Option, []bundle.Option) {
	hasIPv4 := false
	hasIPv6 := false

	for _, cidr := range networkReq.CIDRs {
		if cidr.Addr().Is6() {
			hasIPv6 = true
		} else {
			hasIPv4 = true
		}
	}

	genOpts := []generate.Option{
		generate.WithInstallDisk("/dev/vda"),
	}

	var bundleOpts []bundle.Option

	// full-CLOS nodes have no management net0 at all (only fabric uplinks + a loopback identity): skip the
	// net0 alias/DHCP injection. The per-node config (loopback + BGPInstanceConfig on the fabric NICs) is baked by
	// the configmaker and delivered via the metal-iso config volume.
	if !networkReq.CLOSNoNet0 && contract.MultidocNetworkConfigSupported() {
		aliasConfig := networkcfg.NewLinkAliasConfigV1Alpha1("net0")
		aliasConfig.Selector = networkcfg.LinkSelector{
			Match: cel.MustExpression(cel.ParseBooleanExpression(`link.driver == "virtio_net"`, celenv.LinkLocator())),
		}

		documents := []configconfig.Document{aliasConfig}

		// NoDHCP leaves net0 IPv6-link-local only (BGP-reachability test: identity is on a loopback).
		switch {
		case networkReq.NoDHCP:
			// no DHCP config injected
		case hasIPv4:
			documents = append(documents, networkcfg.NewDHCPv4ConfigV1Alpha1("net0"))
		case hasIPv6:
			documents = append(documents, networkcfg.NewDHCPv6ConfigV1Alpha1("net0"))
		}

		ctr, err := container.New(documents...)
		if err != nil {
			panic(err)
		}

		bundleOpts = append(
			bundleOpts,
			bundle.WithPatch([]configpatcher.Patch{configpatcher.NewStrategicMergePatch(ctr)}),
		)
	} else if !networkReq.CLOSNoNet0 {
		virtioSelector := v1alpha1.IfaceBySelector(v1alpha1.NetworkDeviceSelector{
			NetworkDeviceKernelDriver: "virtio_net",
		})

		genOpts = append(
			genOpts,
			generate.WithNetworkOptions(
				v1alpha1.WithNetworkInterfaceDHCP(virtioSelector, true),
				v1alpha1.WithNetworkInterfaceDHCPv4(virtioSelector, hasIPv4),
				v1alpha1.WithNetworkInterfaceDHCPv6(virtioSelector, hasIPv6),
			),
		)
	}

	if !contract.GrubUseUKICmdlineDefault() {
		genOpts = append(
			genOpts,
			generate.WithInstallExtraKernelArgs([]string{
				"console=ttyS0",
				"reboot=k",
				"panic=1",
				"talos.shutdown=halt",
				"talos.platform=metal",
			}),
		)
	}

	return genOpts, bundleOpts
}

// GetInClusterKubernetesControlPlaneEndpoint returns the Kubernetes control
// plane endpoint. Server runs the TCP loadbalancer on the bridge gateway IP,
// so the client computes the same address from the NetworkRequest.
func (p *Provisioner) GetInClusterKubernetesControlPlaneEndpoint(networkReq provision.NetworkRequest, controlPlanePort int) string {
	return "https://" + nethelpers.JoinHostPort(networkReq.GatewayAddrs[0].String(), controlPlanePort)
}

// GetExternalKubernetesControlPlaneEndpoint returns the Kubernetes control
// plane endpoint. Identical to the in-cluster endpoint — the operator is
// expected to provide routable access from the client to the cluster
// bridge (subnet route, VPN, port-forward, ...).
func (p *Provisioner) GetExternalKubernetesControlPlaneEndpoint(networkReq provision.NetworkRequest, controlPlanePort int) string {
	return p.GetInClusterKubernetesControlPlaneEndpoint(networkReq, controlPlanePort)
}

// GetTalosAPIEndpoints returns nil — talosctl should use control-plane node
// endpoints reached via whatever route the operator has set up to the
// cluster bridge.
func (p *Provisioner) GetTalosAPIEndpoints(provision.NetworkRequest) []string {
	return nil
}

// GetFirstInterface returns the virtio_net selector (the server uses QEMU's
// virtio-net device).
func (p *Provisioner) GetFirstInterface() v1alpha1.IfaceSelector {
	return v1alpha1.IfaceBySelector(v1alpha1.NetworkDeviceSelector{
		NetworkDeviceKernelDriver: "virtio_net",
	})
}

// GetFirstInterfaceName returns "net0" — the alias the server's config
// generation assigns to the virtio-net link.
func (p *Provisioner) GetFirstInterfaceName() string {
	return "net0"
}

// UserDiskName returns the QEMU-disk-by-id path matching what the server's
// VMs will see.
func (p *Provisioner) UserDiskName(index int) string {
	return fmt.Sprintf("/dev/disk/by-id/ata-QEMU_HARDDISK_QM%05d", (index-1)*2+1)
}
